'use client';

import { useState, useEffect } from 'react';
import { Plus, Edit, Trash2, Trophy } from 'lucide-react';
import { achievementService, Achievement } from '@/services/achievement.service';
import { X, Save } from 'lucide-react';

function AchievementModal({
  isOpen, onClose, onSuccess, initial,
}: {
  isOpen: boolean; onClose: () => void; onSuccess: () => void; initial?: Achievement | null;
}) {
  const [form, setForm] = useState({ title: '', placement: '', subtitle: '', year: new Date().getFullYear().toString(), description: '' });
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (isOpen) {
      if (initial) {
        setForm({
          title: initial.title,
          placement: initial.placement,
          subtitle: initial.subtitle || '',
          year: initial.year.toString(),
          description: initial.description || '',
        });
      } else {
        setForm({ title: '', placement: '', subtitle: '', year: new Date().getFullYear().toString(), description: '' });
      }
      setError(null);
    }
  }, [isOpen, initial]);

  if (!isOpen) return null;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    setForm(prev => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.title || !form.placement || !form.year) { setError('Title, Placement, and Year are required'); return; }
    try {
      setSubmitting(true);
      const payload = { title: form.title, placement: form.placement, subtitle: form.subtitle || null, year: parseInt(form.year), description: form.description || null };
      if (initial) await achievementService.update(initial.id, payload);
      else await achievementService.create(payload);
      onSuccess();
      onClose();
    } catch (err: any) // eslint-disable-line @typescript-eslint/no-explicit-any {
      setError(err.message);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <h2 className="text-xl font-bold text-rahula-blue">{initial ? 'Edit Achievement' : 'Add Achievement'}</h2>
          <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors"><X size={20} /></button>
        </div>
        <form id="achievement-form" onSubmit={handleSubmit} className="p-6 space-y-5">
          {error && <div className="p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100">{error}</div>}

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1.5 col-span-2">
              <label className="text-sm font-semibold text-slate-700">Title *</label>
              <input name="title" value={form.title} onChange={handleChange} placeholder="e.g. National Youth Dance Championship" className="w-full px-4 py-2.5 rounded-lg border border-slate-200 bg-slate-50 focus:outline-none focus:ring-2 focus:ring-rahula-blue/20" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-sm font-semibold text-slate-700">Placement *</label>
              <input name="placement" value={form.placement} onChange={handleChange} placeholder="e.g. Gold Medal, 1st Place" className="w-full px-4 py-2.5 rounded-lg border border-slate-200 bg-slate-50 focus:outline-none focus:ring-2 focus:ring-rahula-blue/20" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-sm font-semibold text-slate-700">Year *</label>
              <select name="year" value={form.year} onChange={handleChange} className="w-full px-4 py-2.5 rounded-lg border border-slate-200 bg-slate-50 appearance-none focus:outline-none focus:ring-2 focus:ring-rahula-blue/20">
                {[2026, 2025, 2024, 2023, 2022, 2021, 2020].map(y => <option key={y} value={y}>{y}</option>)}
              </select>
            </div>
            <div className="space-y-1.5 col-span-2">
              <label className="text-sm font-semibold text-slate-700">Subtitle / Category</label>
              <input name="subtitle" value={form.subtitle} onChange={handleChange} placeholder="e.g. Kandyan Dance - Group Performance" className="w-full px-4 py-2.5 rounded-lg border border-slate-200 bg-slate-50 focus:outline-none focus:ring-2 focus:ring-rahula-blue/20" />
            </div>
            <div className="space-y-1.5 col-span-2">
              <label className="text-sm font-semibold text-slate-700">Description</label>
              <textarea name="description" value={form.description} onChange={handleChange} rows={3} placeholder="Additional details about this achievement..." className="w-full px-4 py-2.5 rounded-lg border border-slate-200 bg-slate-50 focus:outline-none focus:ring-2 focus:ring-rahula-blue/20 resize-none" />
            </div>
          </div>
        </form>

        <div className="px-6 py-4 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
          <button type="button" onClick={onClose} className="px-5 py-2.5 rounded-lg font-medium text-slate-600 hover:bg-slate-200 transition-colors" disabled={submitting}>Cancel</button>
          <button type="submit" form="achievement-form" disabled={submitting} className="px-5 py-2.5 rounded-lg font-medium bg-rahula-blue text-white hover:bg-blue-900 transition-colors flex items-center gap-2 disabled:opacity-60">
            {submitting ? <><div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /><span>Saving...</span></> : <><Save size={16} /><span>Save</span></>}
          </button>
        </div>
      </div>
    </div>
  );
}

export default function TeacherAchievementsPage() {
  const [achievements, setAchievements] = useState<Achievement[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<Achievement | null>(null);
  const [deleting, setDeleting] = useState<string | null>(null);

  const load = async () => {
    try { setLoading(true); setAchievements(await achievementService.getAll()); } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const handleDelete = async (a: Achievement) => {
    if (!confirm(`Delete "${a.title}"?`)) return;
    try { setDeleting(a.id); await achievementService.delete(a.id); setAchievements(prev => prev.filter(x => x.id !== a.id)); } finally { setDeleting(null); }
  };

  const openEdit = (a: Achievement) => { setEditing(a); setModalOpen(true); };
  const openAdd = () => { setEditing(null); setModalOpen(true); };

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Achievements</h1>
          <p className="text-sm text-slate-500 mt-1">Manage awards and recognitions displayed on the public site</p>
        </div>
        <button onClick={openAdd} className="flex items-center gap-2 px-5 py-2.5 bg-rahula-blue text-white rounded-xl font-medium hover:bg-blue-900 transition-colors shadow-sm">
          <Plus size={18} /><span>Add Achievement</span>
        </button>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold tracking-wider text-slate-500 uppercase">Achievement</th>
              <th className="px-6 py-4 text-xs font-bold tracking-wider text-slate-500 uppercase">Year</th>
              <th className="px-6 py-4 text-xs font-bold tracking-wider text-slate-500 uppercase">Placement</th>
              <th className="px-6 py-4 text-xs font-bold tracking-wider text-slate-500 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {loading ? (
              <tr><td colSpan={4} className="py-16 text-center"><div className="flex justify-center"><div className="w-7 h-7 border-4 border-slate-200 border-t-rahula-blue rounded-full animate-spin" /></div></td></tr>
            ) : achievements.length === 0 ? (
              <tr><td colSpan={4} className="py-16 text-center text-slate-400">No achievements yet. Click "Add Achievement" to get started.</td></tr>
            ) : (
              achievements.map(a => (
                <tr key={a.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 bg-[#f0f3fb] rounded-lg flex items-center justify-center">
                        <Trophy size={18} className="text-rahula-blue" />
                      </div>
                      <div>
                        <p className="font-semibold text-slate-800 leading-tight">{a.title}</p>
                        {a.subtitle && <p className="text-xs text-slate-400">{a.subtitle}</p>}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="px-2.5 py-1 bg-slate-100 text-slate-600 text-xs font-bold rounded-full">{a.year}</span>
                  </td>
                  <td className="px-6 py-4 text-sm font-medium text-slate-600">{a.placement}</td>
                  <td className="px-6 py-4">
                    <div className="flex items-center justify-end gap-2">
                      <button onClick={() => openEdit(a)} className="p-1.5 text-slate-400 hover:text-rahula-blue hover:bg-slate-100 rounded-lg transition-colors"><Edit size={17} /></button>
                      <button onClick={() => handleDelete(a)} disabled={deleting === a.id} className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-40">
                        {deleting === a.id ? <div className="w-4 h-4 border-2 border-red-300 border-t-red-500 rounded-full animate-spin" /> : <Trash2 size={17} />}
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      <AchievementModal isOpen={modalOpen} onClose={() => setModalOpen(false)} onSuccess={load} initial={editing} />
    </div>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { Search, Upload, Trash2, Play, Eye, Image as ImageIcon } from 'lucide-react';
import { galleryService, GalleryItem, GalleryCategory } from '@/services/gallery.service';
import Image from 'next/image';

const CATEGORY_LABELS: Record<GalleryCategory, string> = {
  PERFORMANCES: 'Performances',
  REHEARSALS: 'Rehearsals',
  AWARDS: 'Awards',
  CULTURAL_EVENTS: 'Cultural Events',
};

function UploadModal({ isOpen, onClose, onSuccess }: { isOpen: boolean; onClose: () => void; onSuccess: () => void }) {
  const [file, setFile] = useState<File | null>(null);
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<GalleryCategory>('PERFORMANCES');
  const [preview, setPreview] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  const reset = () => { setFile(null); setTitle(''); setCategory('PERFORMANCES'); setPreview(null); setError(null); };

  useEffect(() => {
    if (!isOpen) reset();
  }, [isOpen]);

  const handleFile = (f: File) => {
    setFile(f);
    const url = URL.createObjectURL(f);
    setPreview(url);
    if (!title) setTitle(f.name.replace(/\.[^.]+$/, ''));
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const f = e.dataTransfer.files[0];
    if (f) handleFile(f);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file || !title) { setError('File and title are required'); return; }
    try {
      setIsUploading(true);
      await galleryService.upload(file, title, category);
      onSuccess();
      onClose();
    } catch (err: any) // eslint-disable-line @typescript-eslint/no-explicit-any {
      setError(err.message);
    } finally {
      setIsUploading(false);
    }
  };

  if (!isOpen) return null;

  const isVideo = file?.type.startsWith('video/');

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
          <h2 className="text-xl font-bold text-rahula-blue">Upload Media</h2>
          <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors">✕</button>
        </div>
        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          {error && <div className="p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100">{error}</div>}

          {/* Drop zone */}
          <div
            onDrop={handleDrop}
            onDragOver={e => e.preventDefault()}
            onClick={() => fileRef.current?.click()}
            className="border-2 border-dashed border-slate-200 rounded-xl p-6 text-center cursor-pointer hover:border-rahula-blue hover:bg-slate-50/50 transition-all"
          >
            {preview ? (
              <div className="relative w-full aspect-video rounded-lg overflow-hidden">
                {isVideo ? (
                  <video src={preview} className="w-full h-full object-cover rounded-lg" />
                ) : (
                  <Image src={preview} alt="preview" fill className="object-cover rounded-lg" sizes="400px" />
                )}
              </div>
            ) : (
              <div className="flex flex-col items-center gap-2 text-slate-400">
                <Upload size={32} />
                <p className="font-medium text-sm">Drop or click to upload</p>
                <p className="text-xs">Images & Videos up to 50MB</p>
              </div>
            )}
            <input ref={fileRef} type="file" accept="image/*,video/*" className="hidden" onChange={e => { const f = e.target.files?.[0]; if (f) handleFile(f); }} />
          </div>

          {/* Title */}
          <div className="space-y-1.5">
            <label className="text-sm font-semibold text-slate-700">Title *</label>
            <input
              value={title}
              onChange={e => setTitle(e.target.value)}
              placeholder="e.g. Annual Performance 2026"
              className="w-full px-4 py-2.5 rounded-lg border border-slate-200 focus:outline-none focus:ring-2 focus:ring-rahula-blue/20 bg-slate-50"
            />
          </div>

          {/* Category */}
          <div className="space-y-1.5">
            <label className="text-sm font-semibold text-slate-700">Category *</label>
            <select
              value={category}
              onChange={e => setCategory(e.target.value as GalleryCategory)}
              className="w-full px-4 py-2.5 rounded-lg border border-slate-200 focus:outline-none focus:ring-2 focus:ring-rahula-blue/20 bg-slate-50 appearance-none"
            >
              {Object.entries(CATEGORY_LABELS).map(([k, v]) => (
                <option key={k} value={k}>{v}</option>
              ))}
            </select>
          </div>

          <div className="flex justify-end gap-3 pt-2">
            <button type="button" onClick={onClose} className="px-5 py-2.5 rounded-lg font-medium text-slate-600 hover:bg-slate-100 transition-colors">Cancel</button>
            <button
              type="submit"
              disabled={isUploading || !file}
              className="px-5 py-2.5 rounded-lg font-medium bg-rahula-blue text-white hover:bg-blue-900 transition-colors flex items-center gap-2 disabled:opacity-60"
            >
              {isUploading ? <><div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /><span>Uploading...</span></> : <><Upload size={16} /><span>Upload</span></>}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default function TeacherGalleryPage() {
  const [items, setItems] = useState<GalleryItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [deleting, setDeleting] = useState<string | null>(null);

  const load = async () => {
    try {
      setLoading(true);
      const data = await galleryService.getAll();
      setItems(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []);

  const handleDelete = async (id: string) => {
    if (!confirm('Delete this media item?')) return;
    try {
      setDeleting(id);
      await galleryService.delete(id);
      setItems(prev => prev.filter(i => i.id !== id));
    } catch (e) {
      console.error(e);
    } finally {
      setDeleting(null);
    }
  };

  const filtered = items.filter(i =>
    i.title.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-slate-900">Gallery</h1>
        <p className="text-sm text-slate-500 mt-1">Upload and manage photos & videos for the public gallery</p>
      </div>

      {/* Toolbar */}
      <div className="flex flex-col sm:flex-row gap-4 justify-between">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
          <input
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="Search gallery..."
            className="w-full pl-10 pr-4 py-2.5 border border-slate-200 rounded-xl bg-white focus:outline-none focus:ring-2 focus:ring-rahula-blue/20"
          />
        </div>
        <button
          onClick={() => setIsModalOpen(true)}
          className="flex items-center gap-2 px-5 py-2.5 bg-rahula-blue text-white rounded-xl font-medium hover:bg-blue-900 transition-colors shadow-sm"
        >
          <Upload size={18} />
          <span>Upload Media</span>
        </button>
      </div>

      {/* Grid */}
      {loading ? (
        <div className="flex justify-center py-20">
          <div className="w-8 h-8 border-4 border-slate-200 border-t-rahula-blue rounded-full animate-spin" />
        </div>
      ) : filtered.length === 0 ? (
        <div className="bg-white rounded-2xl border border-slate-200 p-20 text-center text-slate-400">
          No media uploaded yet. Click "Upload Media" to add photos or videos.
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
          {filtered.map(item => (
            <div key={item.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col">
              {/* Thumbnail */}
              <div className="relative w-full aspect-video bg-slate-100">
                <Image
                  src={galleryService.getMediaUrl(item.url)}
                  alt={item.title}
                  fill
                  className="object-cover"
                  sizes="(max-width: 768px) 100vw, 33vw"
                />
                {item.mediaType === 'VIDEO' && (
                  <div className="absolute inset-0 flex items-center justify-center">
                    <div className="w-12 h-12 bg-rahula-blue/90 rounded-full flex items-center justify-center shadow-md">
                      <Play className="text-white w-5 h-5 ml-0.5" fill="white" />
                    </div>
                  </div>
                )}
              </div>

              {/* Info */}
              <div className="p-4 flex-1">
                <div className="flex items-start justify-between gap-2">
                  <div>
                    <h4 className="font-semibold text-slate-800 leading-tight">{item.title}</h4>
                    <p className="text-xs text-slate-400 mt-0.5">{new Date(item.date).toLocaleDateString('en-GB')}</p>
                  </div>
                  <span className={`shrink-0 text-xs font-bold px-2 py-0.5 rounded-md ${item.mediaType === 'VIDEO' ? 'bg-blue-100 text-blue-600' : 'bg-green-100 text-green-600'}`}>
                    {item.mediaType === 'VIDEO' ? 'Video' : 'Photo'}
                  </span>
                </div>
                <div className="flex items-center gap-1 mt-2 text-xs text-slate-400">
                  <Eye size={13} />
                  <span>{item.views} views</span>
                </div>
              </div>

              {/* Actions */}
              <div className="px-4 pb-4 flex items-center justify-between border-t border-slate-100 pt-3">
                <a
                  href={galleryService.getMediaUrl(item.url)}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-sm font-semibold text-rahula-blue hover:underline"
                >
                  View
                </a>
                <button
                  onClick={() => handleDelete(item.id)}
                  disabled={deleting === item.id}
                  className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-40"
                >
                  {deleting === item.id ? (
                    <div className="w-4 h-4 border-2 border-red-300 border-t-red-500 rounded-full animate-spin" />
                  ) : (
                    <Trash2 size={16} />
                  )}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      <UploadModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSuccess={load} />
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { X, Save } from 'lucide-react';
import { markService, StudentWithMarks, BulkMarkInput } from '@/services/mark.service';

interface BulkAddMarksModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  students: StudentWithMarks[];
  grade: number;
  term: number;
}

export function BulkAddMarksModal({ isOpen, onClose, onSuccess, students, grade, term }: BulkAddMarksModalProps) {
  const [marksState, setMarksState] = useState<Record<string, { practical: string, paper: string }>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (isOpen) {
      // Initialize state with existing marks if they exist
      const initialState: Record<string, { practical: string, paper: string }> = {};
      students.forEach(student => {
        const termMark = student.marks.find(m => m.term === term);
        initialState[student.id] = {
          practical: termMark && termMark.practicalMark !== null ? termMark.practicalMark.toString() : '',
          paper: termMark && termMark.paperMark !== null ? termMark.paperMark.toString() : ''
        };
      });
      setMarksState(initialState);
      setError(null);
    }
  }, [isOpen, students, term]);

  if (!isOpen) return null;

  const handleInputChange = (studentId: string, field: 'practical' | 'paper', value: string) => {
    // Only allow numbers
    if (value && !/^\d*$/.test(value)) return;

    // Max 100 limit
    if (value && parseInt(value) > 100) return;

    setMarksState(prev => ({
      ...prev,
      [studentId]: {
        ...prev[studentId],
        [field]: value
      }
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    try {
      // Map state into submission payload
      const marksPayload: BulkMarkInput[] = students.map(student => {
        const studentMarks = marksState[student.id] || { practical: '', paper: '' };
        return {
          studentId: student.id,
          grade,
          term,
          practicalMark: studentMarks.practical !== '' ? parseInt(studentMarks.practical) : null,
          paperMark: studentMarks.paper !== '' ? parseInt(studentMarks.paper) : null
        };
      });

      await markService.bulkUpsertMarks(grade, term, marksPayload);

      onSuccess();
      onClose();
    } catch (err: any) // eslint-disable-line @typescript-eslint/no-explicit-any {
      setError(err.message || 'An error occurred while saving marks.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-4xl overflow-hidden flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="px-6 py-4 flex justify-between items-center border-b border-slate-100 bg-slate-50/50">
          <div>
             <h2 className="text-xl font-bold text-rahula-blue">Add/Update Marks - Grade {grade} (Term {term})</h2>
             <p className="text-sm text-slate-500 font-medium">Enter marks for each student (0-100). Leave blank if not available.</p>
          </div>
          <button 
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
          >
            <X size={20} />
          </button>
        </div>

        {/* List of students & inputs */}
        <div className="p-6 overflow-y-auto bg-slate-50" style={{ maxHeight: 'calc(90vh - 150px)' }}>
          {error && (
            <div className="mb-6 p-4 rounded-lg bg-red-50 text-red-600 text-sm border border-red-100">
              {error}
            </div>
          )}

          <form id="bulk-marks-form" onSubmit={handleSubmit} className="space-y-4">
            {students.length === 0 ? (
               <div className="text-center py-8 text-slate-500">No students found in Grade {grade}.</div>
            ) : (
              students.map((student) => (
                <div key={student.id} className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm flex flex-col lg:flex-row gap-6 lg:items-center justify-between">

                  {/* Student Info */}
                  <div className="flex items-center space-x-3 lg:w-1/3">
                    <div className="w-10 h-10 flex items-center justify-center rounded-lg bg-rahula-blue text-white font-bold text-sm shadow-sm shrink-0">
                      {student.name.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <h4 className="font-semibold text-slate-800">{student.name}</h4>
                      <p className="text-xs text-slate-500">Grade {student.grade}</p>
                    </div>
                  </div>

                  {/* Inputs */}
                  <div className="flex gap-4 lg:w-2/3">
                    <div className="flex-1 space-y-1">
                      <label className="text-xs font-semibold text-slate-700">Practical Mark</label>
                      <input 
                        type="text"
                        inputMode="numeric"
                        placeholder="0-100"
                        value={marksState[student.id]?.practical || ''}
                        onChange={(e) => handleInputChange(student.id, 'practical', e.target.value)}
                        className="w-full px-4 py-2.5 rounded-lg border border-slate-200 focus:outline-none focus:ring-2 focus:ring-rahula-blue/20 focus:border-rahula-blue transition-colors"
                      />
                    </div>
                    <div className="flex-1 space-y-1">
                      <label className="text-xs font-semibold text-slate-700">Paper Mark</label>
                      <input 
                        type="text"
                        inputMode="numeric"
                        placeholder="0-100"
                        value={marksState[student.id]?.paper || ''}
                        onChange={(e) => handleInputChange(student.id, 'paper', e.target.value)}
                        className="w-full px-4 py-2.5 rounded-lg border border-slate-200 focus:outline-none focus:ring-2 focus:ring-rahula-blue/20 focus:border-rahula-blue transition-colors"
                      />
                    </div>
                  </div>
                </div>
              ))
            )}
          </form>
        </div>

        {/* Footer */}
        <div className="px-6 py-4 bg-white border-t border-slate-100 flex justify-end space-x-3 mt-auto shrink-0">
          <button 
            type="button"
            onClick={onClose}
            className="px-6 py-2.5 rounded-lg font-medium text-slate-600 border border-slate-200 hover:bg-slate-50 transition-colors disabled:opacity-50"
            disabled={isSubmitting}
          >
            Cancel
          </button>
          <button 
            type="submit"
            form="bulk-marks-form"
            className="px-6 py-2.5 rounded-lg font-medium bg-rahula-blue text-white hover:bg-blue-900 transition-colors shadow-sm focus:ring-2 focus:ring-rahula-blue focus:ring-offset-2 disabled:opacity-75 disabled:cursor-not-allowed flex items-center space-x-2"
            disabled={isSubmitting || students.length === 0}
          >
            {isSubmitting ? (
              <>
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                <span>Saving...</span>
              </>
            ) : (
              <>
                <Save size={18} />
                <span>Save Marks</span>
              </>
            )}
          </button>
        </div>

      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { X } from 'lucide-react';
import { markService, Mark } from '@/services/mark.service';
import { Student } from '@/services/student.service';

interface StudentTermsModalProps {
  isOpen: boolean;
  onClose: () => void;
  student: Student | null;
  currentGrade: number;
}

export function StudentTermsModal({ isOpen, onClose, student, currentGrade }: StudentTermsModalProps) {
  const [marks, setMarks] = useState<Mark[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (isOpen && student) {
      loadMarks();
    }
  }, [isOpen, student]);

  const loadMarks = async () => {
    try {
      setLoading(true);
      const data = await markService.getStudentHistoricalMarks(student!.id);
      // Filter marks for the current grade being viewed
      const currentGradeMarks = data.filter(m => m.grade === currentGrade);
      setMarks(currentGradeMarks);
    } catch (error) {
      console.error('Failed to load historical marks:', error);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen || !student) return null;

  const calculateAverage = (practical: number | null, paper: number | null) => {
    if (practical === null && paper === null) return null;
    return Math.round(((practical || 0) + (paper || 0)) / 2);
  };

  // Helper to find a specific term mark safely
  const getMarkForTerm = (term: number) => {
    return marks.find(m => m.term === term);
  };

  const calculateOverallAverage = () => {
    let total = 0;
    let count = 0;
    [1, 2, 3].forEach(term => {
      const mk = getMarkForTerm(term);
      if (mk && mk.practicalMark !== null && mk.paperMark !== null) {
        total += calculateAverage(mk.practicalMark, mk.paperMark)!;
        count++;
      }
    });
    return count > 0 ? Math.round(total / count) : null;
  };

  const getOverallByCol = (colProvider: (m: Mark) => number | null) => {
    let total = 0;
    let count = 0;
    [1, 2, 3].forEach(term => {
      const mk = getMarkForTerm(term);
      if (mk) {
        const val = colProvider(mk);
        if (val !== null) {
           total += val;
           count++;
        }
      }
    });
    return count > 0 ? Math.round(total / count) : null;
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="px-6 py-4 flex justify-between items-center border-b border-slate-100">
          <div>
            <h2 className="text-xl font-bold text-rahula-blue">{student.name}</h2>
            <p className="text-sm text-slate-500 font-medium mt-0.5">Grade {currentGrade} History</p>
          </div>
          <button 
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
          >
            <X size={20} />
          </button>
        </div>

        {/* Form Body */}
        <div className="p-6 overflow-y-auto">
          {loading ? (
             <div className="flex justify-center items-center py-12">
               <div className="w-8 h-8 border-4 border-slate-200 border-t-rahula-blue rounded-full animate-spin"></div>
             </div>
          ) : (
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="border-b border-slate-200">
                  <th className="py-3 text-xs font-bold tracking-wider text-slate-500 uppercase">Term</th>
                  <th className="py-3 text-xs font-bold tracking-wider text-slate-500 uppercase text-center">Practical</th>
                  <th className="py-3 text-xs font-bold tracking-wider text-slate-500 uppercase text-center">Paper</th>
                  <th className="py-3 text-xs font-bold tracking-wider text-slate-500 uppercase text-center">Average</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {[1, 2, 3].map(term => {
                  const termMark = getMarkForTerm(term);
                  const isAvailable = termMark && (termMark.practicalMark !== null || termMark.paperMark !== null);
                  const average = isAvailable ? calculateAverage(termMark.practicalMark, termMark.paperMark) : null;

                  return (
                    <tr key={term} className="hover:bg-slate-50 transition-colors">
                      <td className="py-4 font-semibold text-slate-700">Term {term}</td>
                      <td className="py-4 text-center font-medium text-slate-600">{termMark?.practicalMark ?? '-'}%</td>
                      <td className="py-4 text-center font-medium text-slate-600">{termMark?.paperMark ?? '-'}%</td>
                      <td className="py-4 text-center">
                         {average !== null ? (
                            <span className="px-3 py-1 bg-green-100 text-green-700 font-bold text-sm rounded-md">
                              {average}%
                            </span>
                         ) : (
                           <span className="text-slate-400">-</span>
                         )}
                      </td>
                    </tr>
                  )
                })}
              </tbody>
              {/* Overall Average Row */}
              <tfoot className="bg-rahula-blue text-white rounded-b-lg">
                <tr>
                  <td className="py-4 px-4 font-bold rounded-bl-lg">Overall Average</td>
                  <td className="py-4 text-center font-bold">{getOverallByCol(m => m.practicalMark) ?? '-'}%</td>
                  <td className="py-4 text-center font-bold">{getOverallByCol(m => m.paperMark) ?? '-'}%</td>
                  <td className="py-4 text-center rounded-br-lg">
                    {calculateOverallAverage() !== null ? (
                      <span className="px-3 py-1 bg-rahula-gold text-white font-bold text-sm rounded-md border border-yellow-500">
                        {calculateOverallAverage()}%
                      </span>
                    ) : (
                      <span>-</span>
                    )}
                  </td>
                </tr>
              </tfoot>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}

